-- Site Reliability Engineer Roadmap seed.
-- Idempotent seed. Safe to rerun.
BEGIN;
CREATE EXTENSION IF NOT EXISTS pgcrypto;

DROP TABLE IF EXISTS seed_edge;
DROP TABLE IF EXISTS seed_node_resource;
DROP TABLE IF EXISTS seed_node_skill;
DROP TABLE IF EXISTS seed_node;
DROP TABLE IF EXISTS seed_resource_map;
DROP TABLE IF EXISTS seed_resource;
DROP TABLE IF EXISTS seed_skill;
DROP TABLE IF EXISTS seed_roadmap_map;

-- Clean previous copy of this specific roadmap only.
DELETE FROM public.progress_event
WHERE roadmap_enrollment_id IN (
    SELECT e.roadmap_enrollment_id
    FROM public.roadmap_enrollment e
    JOIN public.roadmap_version rv ON rv.roadmap_version_id = e.roadmap_version_id
    JOIN public.roadmap r ON r.roadmap_id = rv.roadmap_id
    WHERE r.slug = 'site-reliability-engineer-roadmap'
);

DELETE FROM public.user_node_progress
WHERE roadmap_enrollment_id IN (
    SELECT e.roadmap_enrollment_id
    FROM public.roadmap_enrollment e
    JOIN public.roadmap_version rv ON rv.roadmap_version_id = e.roadmap_version_id
    JOIN public.roadmap r ON r.roadmap_id = rv.roadmap_id
    WHERE r.slug = 'site-reliability-engineer-roadmap'
);

DELETE FROM public.roadmap_enrollment
WHERE roadmap_version_id IN (
    SELECT rv.roadmap_version_id
    FROM public.roadmap_version rv
    JOIN public.roadmap r ON r.roadmap_id = rv.roadmap_id
    WHERE r.slug = 'site-reliability-engineer-roadmap'
);

DELETE FROM public.roadmap
WHERE slug = 'site-reliability-engineer-roadmap';

VALUES (
    'Site Reliability Engineer',
    'site-reliability-engineer',
    'A practical SRE roadmap for CS students covering systems, automation, cloud, Kubernetes, observability, incidents, reliability engineering, security awareness, and production-ready portfolio work.',
    'Infrastructure',
    true
)
ON CONFLICT (slug) DO UPDATE SET
    name = EXCLUDED.name,
    description = EXCLUDED.description,
    category = EXCLUDED.category,
    is_active = true,
    updated_at = now();

DROP TABLE IF EXISTS seed_roadmap_map;
CREATE TEMP TABLE seed_roadmap_map AS
WITH role_row AS (
    SELECT career_role_id FROM public.career_role WHERE slug = 'site-reliability-engineer'
), inserted_roadmap AS (
SELECT career_role_id, (SELECT user_id FROM public."user" WHERE username_normalized = 'contentmanager4' LIMIT 1), 'Site Reliability Engineer Roadmap', 'site-reliability-engineer-roadmap', 'A practical SRE roadmap for CS students covering systems, automation, cloud, Kubernetes, observability, incidents, reliability engineering, security awareness, and production-ready portfolio work.', 'public'
FROM role_row
    RETURNING roadmap_id
), inserted_version AS (
SELECT
    roadmap_id,
    1,
    1,
    0,
    0,
    'initial',
    'published',
    'Site Reliability Engineer Roadmap',
    'A curated static roadmap for CS students with phases, topics, checkpoints, projects, direct skills, resources, and validation-safe persisted mappings.',
    410,
    'TB',
    'manual',
    now()
FROM inserted_roadmap
    RETURNING roadmap_version_id, roadmap_id
)
SELECT roadmap_id, roadmap_version_id FROM inserted_version;

-- Local skills.
DROP TABLE IF EXISTS seed_skill;
CREATE TEMP TABLE seed_skill (slug text PRIMARY KEY, name text NOT NULL, category text NOT NULL, description text NOT NULL) ON COMMIT DROP;


('site-reliability-engineer-alerting-and-runbooks', 'SRE Alerting and Runbooks', 'DevOps & Platform', 'Designing actionable alerts and runbooks that reduce response time, clarify ownership, and support safe recovery.'),
('site-reliability-engineer-architecture', 'Reliability Architecture', 'Architecture & System Design', 'Evaluating service dependencies, redundancy, failure modes, scalability, and reliability tradeoffs.'),
('site-reliability-engineer-automation', 'Reliability Automation', 'DevOps & Platform', 'Automating operational workflows with safe inputs, logging, rollback behavior, and human review points.'),
('site-reliability-engineer-cybersecurity', 'Operational Security', 'Cybersecurity', 'Applying access boundaries, patching, secure configuration, risk reduction, and incident-aware security practices.'),
('site-reliability-engineer-deployment', 'Safe Deployment', 'DevOps & Platform', 'Designing deployment workflows with validation, progressive rollout, monitoring, and rollback plans.'),
('site-reliability-engineer-governance-risk-and-compliance', 'SRE Governance and Compliance', 'Cybersecurity', 'Collecting operational evidence, defining guardrails, and aligning reliability work with governance requirements.'),
('site-reliability-engineer-grafana', 'Grafana Dashboards', 'DevOps & Platform', 'Building dashboards that expose service health, saturation, errors, latency, and incident context.'),
('site-reliability-engineer-opentelemetry', 'OpenTelemetry Instrumentation', 'DevOps & Platform', 'Using traces, metrics, logs, and context propagation to understand distributed service behavior.'),
('site-reliability-engineer-performance-testing', 'Reliability Performance Testing', 'Software Quality', 'Testing latency, throughput, saturation, and failure behavior to guide scaling and resilience decisions.'),
('site-reliability-engineer-postmortems', 'Blameless Postmortems', 'DevOps & Platform', 'Writing timelines, contributing factors, impact analysis, and follow-up actions without blame.'),
('site-reliability-engineer-prometheus', 'Prometheus Monitoring', 'DevOps & Platform', 'Collecting metrics, writing PromQL queries, and connecting alerts to service health and SLOs.'),
('site-reliability-engineer-resilience-patterns', 'Resilience Patterns', 'Architecture & System Design', 'Applying timeouts, retries, circuit breakers, backpressure, and graceful degradation for reliable services.'),
('site-reliability-engineer-systems-programming', 'Systems Programming for SRE', 'Systems & Operating Systems', 'Understanding processes, memory, signals, I/O, and runtime behavior that affect service reliability.'),
('site-reliability-engineer-technical-writing', 'SRE Technical Writing', 'Career & Communication', 'Writing incident updates, runbooks, postmortems, service docs, and operational handoff notes.'),
('site-reliability-engineer-web', 'SRE Web Fundamentals', 'Web', 'Understanding HTTP, DNS, TLS, caching, and web delivery behavior from a reliability perspective.'),
('site-reliability-engineer-security-hardening', 'Security Hardening for Reliability', 'Cybersecurity', 'Reducing production exposure through secure configuration, patching, identity controls, network boundaries, and verification checks.');

SELECT ss.name, ss.slug, ss.category, ss.description, true
FROM seed_skill ss
ON CONFLICT (slug) DO UPDATE SET
    name = EXCLUDED.name,
    category = EXCLUDED.category,
    description = EXCLUDED.description,
    is_active = true,
    updated_at = now();

-- Learning resources.
DROP TABLE IF EXISTS seed_resource;
CREATE TEMP TABLE seed_resource (resource_key text PRIMARY KEY, title text NOT NULL, url text NOT NULL, resource_type text NOT NULL, description text NOT NULL, provider text, difficulty_level text) ON COMMIT DROP;
,
('urlpass-aws-iam-policy-evaluation', 'AWS IAM Policy Evaluation Logic', 'https://docs.aws.amazon.com/IAM/latest/UserGuide/reference_policies_evaluation-logic.html', 'documentation', 'AWS IAM documentation explaining how policies are evaluated across identities, resources, and permission boundaries.', 'AWS', 'intermediate')
,
('urlpass-api-design-ms', 'API Design Best Practices', 'https://learn.microsoft.com/en-us/azure/architecture/best-practices/api-design', 'documentation', 'Microsoft Azure Architecture Center guidance for practical REST API design.', 'Microsoft Learn', 'intermediate'),
