('qe-owasp-secrets', 'OWASP Secrets Management Cheat Sheet', 'https://cheatsheetseries.owasp.org/cheatsheets/Secrets_Management_Cheat_Sheet.html', 'documentation', 'OWASP guidance for managing secrets, credentials, rotation, and storage.', 'OWASP', 'intermediate'),
('qe-tcp-ip-guide', 'The TCP/IP Guide', 'http://www.tcpipguide.com/free/', 'book', 'Reference guide to TCP/IP protocols, addressing, routing, transport, and application layers.', 'TCP/IP Guide', 'intermediate'),
('qe-pinecone-vector-db', 'What is a Vector Database?', 'https://www.pinecone.io/learn/vector-database/', 'article', 'Pinecone article explaining vector databases, embeddings, and similarity search concepts.', 'Pinecone', 'intermediate'),
('qe-azure-architecture-center', 'Azure Architecture Center', 'https://learn.microsoft.com/en-us/azure/architecture/', 'documentation', 'Microsoft guidance for Azure architecture patterns, reliability, security, and operations.', 'Microsoft Learn', 'intermediate');

SELECT sr.title, sr.url, sr.resource_type, sr.description, sr.provider, sr.difficulty_level, 'en', 'verified'
FROM (
    SELECT DISTINCT ON (url) title, url, resource_type, description, provider, difficulty_level
    FROM seed_resource
    ORDER BY url, resource_key
) sr
WHERE NOT EXISTS (SELECT 1 FROM public.learning_resource lr WHERE lr.url = sr.url);

DROP TABLE IF EXISTS seed_resource_map;
CREATE TEMP TABLE seed_resource_map AS
SELECT sr.resource_key, lr.learning_resource_id
FROM seed_resource sr
JOIN (
    SELECT DISTINCT ON (url) learning_resource_id, url
    FROM public.learning_resource
    ORDER BY url, created_at DESC, learning_resource_id
) lr ON lr.url = sr.url;

-- Roadmap nodes.
DROP TABLE IF EXISTS seed_node;
CREATE TEMP TABLE seed_node (
    node_id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
    node_key text UNIQUE NOT NULL,
    parent_key text,
    order_index int NOT NULL,
    node_type text NOT NULL,
    checkpoint_type text,
    selection_type text,
    required_count int,
    title text NOT NULL,
    description text,
    layout_role text NOT NULL,
    estimated_hours int,
    difficulty_level text,
    metadata jsonb NOT NULL,
    is_required boolean NOT NULL,
    is_trackable boolean NOT NULL,
    learning_outcomes jsonb NOT NULL,
    completion_criteria jsonb NOT NULL
) ON COMMIT DROP;


SELECT sn.node_id, m.roadmap_version_id, parent.node_id, sn.node_key, sn.node_type, sn.checkpoint_type, sn.selection_type, sn.required_count, sn.title, sn.description, sn.order_index, sn.layout_role, sn.estimated_hours, sn.difficulty_level, sn.metadata, sn.is_required, sn.is_trackable, sn.learning_outcomes, sn.completion_criteria
FROM seed_node sn
CROSS JOIN seed_roadmap_map m
LEFT JOIN seed_node parent ON parent.node_key = sn.parent_key
ON CONFLICT (roadmap_version_id, slug) DO UPDATE SET
    parent_node_id = EXCLUDED.parent_node_id,
    node_type = EXCLUDED.node_type,
    checkpoint_type = EXCLUDED.checkpoint_type,
    selection_type = EXCLUDED.selection_type,
    required_count = EXCLUDED.required_count,
    title = EXCLUDED.title,
    description = EXCLUDED.description,
    order_index = EXCLUDED.order_index,
    layout_role = EXCLUDED.layout_role,
    estimated_hours = EXCLUDED.estimated_hours,
    difficulty_level = EXCLUDED.difficulty_level,
    metadata = EXCLUDED.metadata,
    is_required = EXCLUDED.is_required,
    is_trackable = EXCLUDED.is_trackable,
    learning_outcomes = EXCLUDED.learning_outcomes,
    completion_criteria = EXCLUDED.completion_criteria;

